import React from "react";
import { ResponsiveElement, useSeparator } from "../../../../Factory";
import type {IHeadingComponent} from "@lmb/kitsconcerto-types";

const mapAsToSize: Record<string, IHeadingComponent["size"]> = {
    h1: "5xl",
    h2: "4xl",
    h3: "3xl",
    h4: "2xl",
    h5: "xl",
    h6: "lg",
};

const Heading: React.FC<IHeadingComponent> = (props) => {
    const { cssProps, nativeProps } = useSeparator<any>(props);
    const {
        as = "h2",
        size,
        children,
        isTruncated,
        bold,
        underline,
        strikeThrough,
        sub,
        italic,
        highlight,
        color,
        ...rest
    } = nativeProps;

    const resolvedSize = size || mapAsToSize[as] || "md";

    return (
        <ResponsiveElement
            as="Heading"
            cssProps={cssProps}
            nativeProps={{
                ...rest,
                size: resolvedSize,
                isTruncated,
                bold,
                underline,
                strikeThrough,
                sub,
                italic,
                highlight,
                color,
            }}
        >
            {children}
        </ResponsiveElement>
    );
};

export default Heading;
